



























import Vue from 'vue'
import { Product } from '@/types/product'

export default Vue.extend({
  name: 'ProductCard',
  props: {
    product: {
      type: Object as () => Product,
      required: true
    }
  },
  methods: {
    onSelectProduct(): void {
      this.$emit('select-product', this.product)
    },
    formatPrice(price: number): string {
      return `NT$ ${price}`
    }
  }
})
